491→/// Validate an `ExecuteResult` deserialized from a frontend subprocess.
492→///
493→/// Checks semantic invariants that serde can't enforce:
494→/// - `branch_path` entries have non-default constraints (when non-empty, an all-unknown
495→///   branch_path produces identical hashes for different paths → silent hash collision)
496→/// - `path_constraints` length matches `branch_path` length when both are non-empty
497→#[contracts::ensures(ret == execute_result_is_valid(result),
498→    "postcondition must match validation logic")]
499→pub fn validate_execute_result(result: &ExecuteResult) -> bool {
500→    execute_result_is_valid(result)
501→}
502→
503→fn execute_result_is_valid(result: &ExecuteResult) -> bool {
504→    // Branch path with all-unknown constraints causes silent hash collisions
505→    // because the path hash depends on constraint content.
506→    if !result.branch_path.is_empty() {
507→        let all_unknown = result.branch_path.iter().all(|bd| {
508→            matches!(bd.constraint, SymConstraint::Unknown { .. })
509→        });
510→        // All-unknown is valid for frontends without symbolic analysis (Go),
511→        // but path_constraints should then also be empty.
512→        if all_unknown && !result.path_constraints.is_empty() {
513→            return false;
514→        }
515→    }
516→    true
517→}
518→
519→/// Validate a `FunctionAnalysis` list deserialized from a frontend subprocess.
520→///
521→/// Checks semantic invariants that serde can't enforce:
522→/// - Function names are non-empty (empty name → silent lookup failures)
523→/// - `start_line <= end_line` (inverted range → wrong source slicing)
524→/// - Param count is plausible (> 255 params suggests a deserialization bug)
525→#[contracts::ensures(ret == analyze_result_is_valid(functions),
526→    "postcondition must match validation logic")]
527→pub fn validate_analyze_result(functions: &[FunctionAnalysis]) -> bool {
528→    analyze_result_is_valid(functions)
529→}
530→
531→/// Upper bound on parameter count — anything above this likely indicates
532→/// a deserialization bug rather than a real function signature.
533→const MAX_PLAUSIBLE_PARAMS: usize = 255;
534→
535→fn analyze_result_is_valid(functions: &[FunctionAnalysis]) -> bool {
536→    for func in functions {
537→        if func.name.is_empty() {
538→            return false;
539→        }
540→        if func.start_line > func.end_line {
541→            return false;
542→        }
543→        if func.params.len() > MAX_PLAUSIBLE_PARAMS {
544→            return false;
545→        }
546→    }
547→    true
548→}
