326→// TestPropertyHandlerResponseOrdering verifies that for any sequence of valid
327→// requests, the handler produces responses with matching IDs in the same order
328→// (no reordering, no drops). Shutdown terminates processing.
329→func TestPropertyHandlerResponseOrdering(t *testing.T) {
330→	rapid.Check(t, func(t *rapid.T) {
331→		// Generate 1-5 non-shutdown commands followed by shutdown
332→		n := rapid.IntRange(1, 5).Draw(t, "numCommands")
333→		var lines []string
334→		var expectedIDs []int
335→
336→		for i := 0; i < n; i++ {
337→			cmd := genNonShutdownCommand().Draw(t, fmt.Sprintf("cmd%d", i))
338→			line := fmt.Sprintf(`{"protocol_version":%q,"id":%d,"command":%q}`, ProtocolVersion, i+1, cmd)
339→			lines = append(lines, line)
340→			expectedIDs = append(expectedIDs, i+1)
341→		}
342→		// Append shutdown
343→		shutdownID := n + 1
344→		lines = append(lines, fmt.Sprintf(`{"protocol_version":%q,"id":%d,"command":"shutdown"}`, ProtocolVersion, shutdownID))
345→		expectedIDs = append(expectedIDs, shutdownID)
346→
347→		input := strings.Join(lines, "\n") + "\n"
348→		var out bytes.Buffer
349→		h := NewHandlerWithLogLevel(strings.NewReader(input), &out, &bytes.Buffer{}, "error")
