  "type": "object",
  "required": ["protocol_version", "id", "status"],
  "properties": {
    "protocol_version": {
      "type": "string",
      "description": "Protocol version for compatibility checking.",
      "pattern": "^\\d+\\.\\d+\\.\\d+$"
    },
    "id": {
      "type": "integer",
      "minimum": 0,
      "description": "Request ID this response corresponds to."
    },
    "status": {
      "type": "string",
      "enum": ["handshake", "analyze", "instrument", "execute", "setup", "teardown_ack", "generate", "shutdown_ack", "error"],
      "description": "The response type, matching the originating command."
    }
  },
  "oneOf": [
    { "$ref": "#/$defs/handshake_response" },
    { "$ref": "#/$defs/analyze_response" },
    { "$ref": "#/$defs/instrument_response" },
    { "$ref": "#/$defs/execute_response" },
    { "$ref": "#/$defs/generate_response" },
    { "$ref": "#/$defs/shutdown_ack_response" },
    { "$ref": "#/$defs/error_response" }
  ],
  "$defs": {
    "handshake_response": {
      "type": "object",
      "properties": {
        "status": { "const": "handshake" },
        "frontend_version": {
          "type": "string",
          "description": "Protocol version the frontend supports."
        },
        "language": {
          "type": "string",
          "description": "Language this frontend handles (e.g., 'typescript', 'go')."
        },
        "capabilities": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Capabilities supported by the frontend."
        }
      },
      "required": ["status", "frontend_version", "language", "capabilities"]
    },
    "analyze_response": {
      "type": "object",
      "properties": {
        "status": { "const": "analyze" },
        "functions": {
          "type": "array",
          "items": { "$ref": "function-analysis.schema.json" },
          "description": "Functions found and analyzed."
        }
      },
      "required": ["status", "functions"]
    },
    "instrument_response": {
      "type": "object",
      "properties": {
        "status": { "const": "instrument" },
        "instrumented": {
          "type": "boolean",
          "description": "Whether instrumentation succeeded."
        },
        "output_file": {
          "type": ["string", "null"],
          "description": "Path to the instrumented output file, if applicable."
        },
        "instrumentable_line_count": {
          "type": "integer",
          "minimum": 0,
          "description": "Number of executable statement lines the instrumentor inserted record calls for."
        }
      },
      "required": ["status", "instrumented"]
    },
    "execute_response": {
      "type": "object",
      "properties": {
        "status": { "const": "execute" },
        "return_value": {
          "description": "Return value from the function, if it returned normally."
        },
        "thrown_error": {
          "oneOf": [
            { "$ref": "error-info.schema.json" },
            { "type": "null" }
          ],
          "description": "Error thrown during execution, if any."
        },
        "branch_path": {
          "type": "array",
          "items": { "$ref": "branch-decision.schema.json" },
          "description": "Branch decisions recorded during execution."
        },
        "lines_executed": {
          "type": "array",
          "items": { "type": "integer" },
          "description": "Source lines executed."
        },
        "calls_to_external": {
          "type": "array",
          "items": { "$ref": "external-call.schema.json" },
          "description": "Calls to external dependencies observed."
        },
        "path_constraints": {
          "type": "array",
          "items": { "$ref": "sym-constraint.schema.json" },
          "description": "Symbolic path constraints collected."
        },
        "side_effects": {
          "type": "array",
          "items": { "$ref": "side-effect.schema.json" },
