/**
 * Property-based tests using fast-check for protocol types and SymExpr.
 *
 * Validates serialization round-trips and structural invariants that
 * hand-written fixtures might miss.
 */
import fc from "fast-check";
import ts from "typescript";
import type {
  BinOpKind,
  UnOpKind,
  SymExpr,
  SymExprConst,
  TypeInfo,
  ComplexKind,
  BranchType,
  BranchDecision,
  SymConstraint,
  ErrorCode,
} from "./protocol.js";
import {
  ALL_ERROR_CODES,
  SideEffect,
  PerformanceMetrics,
  TraceEvent,
  ScopeEvent,
  HandshakeRequest,
  AnalyzeRequest,
  ExecuteRequest,
  ShutdownRequest,
  SetupRequest,
  TeardownRequest,
  SetupLevel,
  SetupContextEntry,
  SetupContextStack,
  Request,
  HandshakeResponse,
  AnalyzeResponse,
  ErrorResponse,
  Response,
  FunctionAnalysis,
  ParamInfo,
  BranchInfo,
  ErrorInfo,
} from "./protocol.js";
import { PROTOCOL_VERSION } from "./protocol.js";
import { buildSymExpr, buildSymExprWithFlow } from "./instrumentor.js";

// ---------------------------------------------------------------------------
// Arbitraries — leaf types
// ---------------------------------------------------------------------------

const arbIdent = fc.stringMatching(/^[a-zA-Z_][a-zA-Z0-9_]{0,12}$/);
const arbShortString = fc.string({ maxLength: 30 });

const arbBinOpKind: fc.Arbitrary<BinOpKind> = fc.constantFrom(
  "eq", "ne", "lt", "le", "gt", "ge",
  "add", "sub", "mul", "div", "mod",
  "and", "or",
  "bitwise_and", "bitwise_or", "bitwise_xor",
  "in", "instance_of",
);

const arbUnOpKind: fc.Arbitrary<UnOpKind> = fc.constantFrom(
  "not", "neg", "bitwise_not", "typeof",
);

const arbComplexKind: fc.Arbitrary<ComplexKind> = fc.constantFrom(
  "date", "date_time", "time", "duration",
  "reg_exp", "char", "symbol",
  "big_int", "big_decimal", "complex", "rational", "range",
  "buffer", "bit_set",
  "error", "option", "result",
  "closure", "iterator",
  "url", "ip_address",
  "uuid", "path",
  "money", "sem_ver", "email", "mime_type", "color", "geo_point", "locale",
  "rune", "go_byte",
);

const arbBranchType: fc.Arbitrary<BranchType> = fc.constantFrom(
  "if", "else_if", "switch", "ternary",
  "logical_and", "logical_or", "while", "for",
);

const arbErrorCode: fc.Arbitrary<ErrorCode> = fc.constantFrom(
  ...ALL_ERROR_CODES,
);

// ---------------------------------------------------------------------------
// Arbitraries — recursive types
// ---------------------------------------------------------------------------

const arbSymExprConst: fc.Arbitrary<SymExprConst> = fc.oneof(
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("int" as const), value: fc.integer({ min: -10000, max: 10000 }) }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("float" as const), value: fc.integer({ min: -1000, max: 1000 }) }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("str" as const), value: arbShortString }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("bool" as const), value: fc.boolean() }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("null" as const) }),
  fc.record({ kind: fc.constant("const" as const), type: fc.constant("undefined" as const) }),
);

const arbSymExpr: fc.Arbitrary<SymExpr> = fc.letrec<{ expr: SymExpr }>(tie => ({
  expr: fc.oneof(
    { depthIdentifier: "symexpr", maxDepth: 3 },
    fc.record({
      kind: fc.constant("param" as const),
      name: arbIdent,
      path: fc.array(arbIdent, { maxLength: 3 }),
    }),
    arbSymExprConst,
    fc.record({ kind: fc.constant("unknown" as const) }),
    fc.record({
      kind: fc.constant("bin_op" as const),
      op: arbBinOpKind,
      left: tie("expr"),
      right: tie("expr"),
    }),
    fc.record({
      kind: fc.constant("un_op" as const),
      op: arbUnOpKind,
      operand: tie("expr"),
    }),
  ),
})).expr;

const arbTypeInfoLeaf: fc.Arbitrary<TypeInfo> = fc.oneof(
  fc.record({ kind: fc.constant("int" as const) }),
  fc.record({ kind: fc.constant("float" as const) }),
  fc.record({ kind: fc.constant("str" as const) }),
  fc.record({ kind: fc.constant("bool" as const) }),
  fc.record({ kind: fc.constant("unknown" as const) }),
  fc.record({ kind: fc.constant("opaque" as const), label: arbIdent }),
);

const arbTypeInfo: fc.Arbitrary<TypeInfo> = fc.letrec<{ ti: TypeInfo }>(tie => ({
  ti: fc.oneof(
    { depthIdentifier: "typeinfo", maxDepth: 2 },
    arbTypeInfoLeaf,
    fc.record({ kind: fc.constant("array" as const), element: tie("ti") }),
    fc.record({
      kind: fc.constant("nullable" as const),
      inner: tie("ti"),
    }),
    fc.record({
      kind: fc.constant("union" as const),
      variants: fc.array(tie("ti"), { minLength: 2, maxLength: 4 }),
    }),
  ),
})).ti;

// ---------------------------------------------------------------------------
// Arbitraries — protocol records
// ---------------------------------------------------------------------------

const arbSymConstraint: fc.Arbitrary<SymConstraint> = fc.oneof(
  fc.record({ kind: fc.constant("expr" as const), expr: arbSymExpr }),
  fc.record({ kind: fc.constant("unknown" as const), hint: arbShortString }),
);

const arbBranchDecision: fc.Arbitrary<BranchDecision> = fc.record({
  branch_id: fc.nat(100),
  line: fc.integer({ min: 1, max: 500 }),
  taken: fc.boolean(),
  constraint: arbSymConstraint,
});

const arbScopeEvent: fc.Arbitrary<ScopeEvent> = fc.oneof(
  fc.record({ kind: fc.constant("loop_enter" as const), loop_id: fc.nat(20) }),
  fc.record({ kind: fc.constant("loop_exit" as const), loop_id: fc.nat(20) }),
  fc.record({ kind: fc.constant("call_enter" as const), call_site_id: fc.nat(20) }),
  fc.record({ kind: fc.constant("call_exit" as const), call_site_id: fc.nat(20) }),
);

const arbTraceEvent: fc.Arbitrary<TraceEvent> = fc.oneof(
  fc.record({ type: fc.constant("branch" as const), decision: arbBranchDecision }),
  fc.record({ type: fc.constant("scope" as const), event: arbScopeEvent }),
);

const arbPerformanceMetrics: fc.Arbitrary<PerformanceMetrics> = fc.record({
  wall_time_ms: fc.nat(10000),
  cpu_time_us: fc.nat(10000000),
  heap_used_bytes: fc.nat(100000000),
  heap_allocated_bytes: fc.nat(100000000),
});

const arbErrorInfo: fc.Arbitrary<ErrorInfo> = fc.record({
  error_type: arbIdent,
  message: arbShortString,
  stack: fc.option(arbShortString, { nil: null }),
});

const arbSideEffect: fc.Arbitrary<SideEffect> = fc.oneof(
  fc.record({ kind: fc.constant("console_output" as const), level: arbIdent, message: arbShortString }),
  fc.record({ kind: fc.constant("global_mutation" as const), name: arbIdent }),
  fc.record({
    kind: fc.constant("thrown_error" as const),
    error_type: arbIdent,
    message: arbShortString,
    stack: fc.option(arbShortString, { nil: null }),
  }),
);

const arbParamInfo: fc.Arbitrary<ParamInfo> = fc.record({
  name: arbIdent,
  type: arbTypeInfo,
});

const arbBranchInfo: fc.Arbitrary<BranchInfo> = fc.record({
  id: fc.nat(100),
  line: fc.integer({ min: 1, max: 500 }),
  condition_text: arbShortString,
  condition: fc.option(arbSymExpr, { nil: null }),
  branch_type: arbBranchType,
});

const arbFunctionAnalysis: fc.Arbitrary<FunctionAnalysis> = fc.record({
  name: arbIdent,
  exported: fc.boolean(),
  params: fc.array(arbParamInfo, { maxLength: 4 }),
  branches: fc.array(arbBranchInfo, { maxLength: 4 }),
  dependencies: fc.constant([]),
  return_type: arbTypeInfo,
  start_line: fc.integer({ min: 1, max: 500 }),
  end_line: fc.integer({ min: 1, max: 500 }),
});

// ---------------------------------------------------------------------------
// Arbitraries — setup types
// ---------------------------------------------------------------------------

const arbSetupLevel: fc.Arbitrary<SetupLevel> = fc.constantFrom(
  "session", "file", "function", "execution",
);

const arbSetupContextEntry: fc.Arbitrary<SetupContextEntry> = fc.record({
  level: arbSetupLevel,
  context: fc.oneof(fc.integer(), fc.string({ maxLength: 10 }), fc.constant(null), fc.record({ id: fc.nat(100) })),
});

const arbSetupContextStack: fc.Arbitrary<SetupContextStack> = fc.record({
  contexts: fc.array(arbSetupContextEntry, { maxLength: 4 }),
});

// ---------------------------------------------------------------------------
// Arbitraries — full protocol messages
// ---------------------------------------------------------------------------

const arbRequest: fc.Arbitrary<Request> = fc.oneof(
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("handshake" as const),
    capabilities: fc.array(arbIdent, { maxLength: 3 }),
  }) as fc.Arbitrary<HandshakeRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("analyze" as const),
    file: arbIdent,
  }) as fc.Arbitrary<AnalyzeRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("execute" as const),
    function: arbIdent,
    inputs: fc.array(fc.oneof(fc.integer(), fc.constant("hello"), fc.boolean()), { maxLength: 4 }),
    mocks: fc.constant([]),
  }) as fc.Arbitrary<ExecuteRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("setup" as const),
    file: arbIdent,
    scope: arbIdent,
    level: arbSetupLevel,
  }) as fc.Arbitrary<SetupRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("teardown" as const),
    scope: arbIdent,
    level: arbSetupLevel,
  }) as fc.Arbitrary<TeardownRequest>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("shutdown" as const),
  }) as fc.Arbitrary<ShutdownRequest>,
);

const arbResponse: fc.Arbitrary<Response> = fc.oneof(
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    status: fc.constant("handshake" as const),
    frontend_version: fc.constant(PROTOCOL_VERSION),
    language: fc.constant("typescript"),
    capabilities: fc.array(arbIdent, { maxLength: 3 }),
  }) as fc.Arbitrary<HandshakeResponse>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    status: fc.constant("analyze" as const),
    functions: fc.array(arbFunctionAnalysis, { maxLength: 3 }),
  }) as fc.Arbitrary<AnalyzeResponse>,
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    status: fc.constant("error" as const),
    code: arbErrorCode,
    message: arbShortString,
  }) as fc.Arbitrary<ErrorResponse>,
);

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("property: protocol message round-trips", () => {
  it("Request survives JSON round-trip", () => {
    fc.assert(
      fc.property(arbRequest, (req) => {
        const json = JSON.stringify(req);
        const decoded = JSON.parse(json) as Request;
        expect(decoded).toEqual(req);
      }),
    );
  });

  it("Response survives JSON round-trip", () => {
    fc.assert(
      fc.property(arbResponse, (resp) => {
        const json = JSON.stringify(resp);
        const decoded = JSON.parse(json) as Response;
        expect(decoded).toEqual(resp);
      }),
    );
  });

  it("SetupContextStack survives JSON round-trip", () => {
    fc.assert(
      fc.property(arbSetupContextStack, (stack) => {
        const json = JSON.stringify(stack);
        const decoded = JSON.parse(json) as SetupContextStack;
        expect(decoded).toEqual(stack);
        expect(decoded.contexts).toHaveLength(stack.contexts.length);
      }),
    );
  });

  it("SetupRequest with parent_context survives JSON round-trip", () => {
    fc.assert(
      fc.property(
        fc.record({
          protocol_version: fc.constant(PROTOCOL_VERSION),
          id: fc.nat(1000),
          command: fc.constant("setup" as const),
          file: arbIdent,
          scope: arbIdent,
          level: arbSetupLevel,
          parent_context: fc.option(arbSetupContextStack, { nil: null }),
        }),
        (req) => {
          const json = JSON.stringify(req);
          const decoded = JSON.parse(json) as SetupRequest;
          expect(decoded.command).toBe("setup");
          expect(decoded.scope).toBe(req.scope);
          expect(decoded.level).toBe(req.level);
        },
      ),
    );
  });

  it("TeardownRequest with level survives JSON round-trip", () => {
    fc.assert(
      fc.property(
        fc.record({
          protocol_version: fc.constant(PROTOCOL_VERSION),
          id: fc.nat(1000),
          command: fc.constant("teardown" as const),
          scope: arbIdent,
          level: arbSetupLevel,
        }),
        (req) => {
          const json = JSON.stringify(req);
          const decoded = JSON.parse(json) as TeardownRequest;
          expect(decoded).toEqual(req);
        },
      ),
    );
  });
});

describe("property: SymExpr structural validity", () => {
  const VALID_KINDS = new Set(["param", "const", "bin_op", "un_op", "call", "unknown"]);

  it("every generated SymExpr has a valid kind tag", () => {
    fc.assert(
      fc.property(arbSymExpr, (expr) => {
        expect(VALID_KINDS.has(expr.kind)).toBe(true);
      }),
    );
  });

  it("bin_op always has left, right, and op", () => {
    fc.assert(
      fc.property(arbSymExpr, (expr) => {
        if (expr.kind === "bin_op") {
          expect(expr.left).toBeDefined();
          expect(expr.right).toBeDefined();
          expect(expr.op).toBeDefined();
        }
      }),
    );
  });

  it("un_op always has operand and op", () => {
    fc.assert(
      fc.property(arbSymExpr, (expr) => {
        if (expr.kind === "un_op") {
          expect(expr.operand).toBeDefined();
          expect(expr.op).toBeDefined();
        }
      }),
    );
  });

  it("param always has name and path", () => {
    fc.assert(
      fc.property(arbSymExpr, (expr) => {
        if (expr.kind === "param") {
          expect(typeof expr.name).toBe("string");
          expect(Array.isArray(expr.path)).toBe(true);
        }
      }),
    );
  });

  it("SymExpr round-trips through JSON", () => {
    fc.assert(
      fc.property(arbSymExpr, (expr) => {
        const json = JSON.stringify(expr);
        const decoded = JSON.parse(json) as SymExpr;
        expect(decoded).toEqual(expr);
      }),
    );
  });
});

describe("property: TypeInfo structural validity", () => {
  const VALID_KINDS = new Set([
    "int", "float", "str", "bool", "unknown", "opaque",
    "array", "object", "union", "nullable", "complex",
  ]);

  it("every generated TypeInfo has a valid kind tag", () => {
    fc.assert(
      fc.property(arbTypeInfo, (ti) => {
        expect(VALID_KINDS.has(ti.kind)).toBe(true);
      }),
    );
  });

  it("TypeInfo round-trips through JSON", () => {
    fc.assert(
      fc.property(arbTypeInfo, (ti) => {
        const json = JSON.stringify(ti);
        const decoded = JSON.parse(json) as TypeInfo;
        expect(decoded).toEqual(ti);
      }),
    );
  });
});

describe("property: BranchDecision round-trips", () => {
  it("BranchDecision survives JSON round-trip", () => {
    fc.assert(
      fc.property(arbBranchDecision, (bd) => {
        const json = JSON.stringify(bd);
        const decoded = JSON.parse(json) as BranchDecision;
        expect(decoded).toEqual(bd);
      }),
    );
  });
});

describe("property: TraceEvent round-trips", () => {
  it("TraceEvent survives JSON round-trip", () => {
    fc.assert(
      fc.property(arbTraceEvent, (te) => {
        const json = JSON.stringify(te);
        const decoded = JSON.parse(json) as TraceEvent;
        expect(decoded).toEqual(te);
      }),
    );
  });
});

// ---------------------------------------------------------------------------
// SymExpr builder parity tests
// ---------------------------------------------------------------------------

/**
 * Parse a TS expression string and extract the expression AST node.
 * Wraps the expression in `const __expr = EXPR;` so the compiler parses it.
 */
function parseExpr(exprSource: string): ts.Expression {
  const source = `const __expr = ${exprSource};`;
  const sf = ts.createSourceFile("test.ts", source, ts.ScriptTarget.ESNext, true);
  const stmt = sf.statements[0] as ts.VariableStatement;
  const decl = stmt.declarationList.declarations[0]!;
  return decl.initializer!;
}

/**
 * Check if a SymExpr tree contains at least one non-unknown leaf.
 * When all leaves are unknown, buildSymExprWithFlow intentionally returns
 * unknown as an optimization — this is not a parity violation.
 */
function hasNonUnknownLeaf(expr: SymExpr): boolean {
  if (expr.kind === "param" || expr.kind === "const") return true;
  if (expr.kind === "bin_op") return hasNonUnknownLeaf(expr.left) || hasNonUnknownLeaf(expr.right);
  if (expr.kind === "un_op") return hasNonUnknownLeaf(expr.operand);
  if (expr.kind === "call") {
    const recOk = expr.receiver ? hasNonUnknownLeaf(expr.receiver) : false;
    return recOk || expr.args.some(hasNonUnknownLeaf);
  }
  return false;
}

const PARAM_NAME = "x";
const paramNames = new Set([PARAM_NAME]);
const resolveName = (name: string): SymExpr | undefined =>
  name === PARAM_NAME ? { kind: "param", name: PARAM_NAME, path: [] } : undefined;

/** Generator for binary operator source tokens that binaryTokenToOp handles. */
const arbBinOp = fc.constantFrom(
  "===", "!==", "==", "!=",
  "<", "<=", ">", ">=",
  "+", "-", "*", "/", "%",
  "&&", "||",
  "&", "|", "^",
);

/** Generator for unary prefix operator source tokens. */
const arbUnOp = fc.constantFrom("!", "-", "~");

/**
 * Generator for TypeScript expression source code involving param `x`.
 * Each generated expression should be parseable and involve the param
 * so at least one builder returns a non-unknown result.
 */
const arbExprSource: fc.Arbitrary<string> = fc.letrec<{ expr: string }>(tie => ({
  expr: fc.oneof(
    { depthIdentifier: "exprdepth", maxDepth: 2 },
    // Param identifier
    fc.constant(PARAM_NAME),
    // Numeric literals
    fc.integer({ min: -1000, max: 1000 }).map(n => String(n < 0 ? `(${n})` : n)),
    // String literals
    fc.stringMatching(/^[a-z]{0,5}$/).map(s => `"${s}"`),
    // Boolean literals
    fc.boolean().map(b => String(b)),
    // null
    fc.constant("null"),
    // Property access on param
    fc.stringMatching(/^[a-z]{1,5}$/).map(prop => `${PARAM_NAME}.${prop}`),
    // Binary expression with param
    arbBinOp.chain(op =>
      tie("expr").map(right => `(${PARAM_NAME} ${op} ${right})`),
    ),
    // Unary prefix
    arbUnOp.map(op => `(${op}${PARAM_NAME})`),
    // typeof
    fc.constant(`(typeof ${PARAM_NAME})`),
    // Method call on param
    fc.stringMatching(/^[a-z]{1,5}$/).map(m => `${PARAM_NAME}.${m}()`),
    // Method call with argument
    fc.tuple(
      fc.stringMatching(/^[a-z]{1,5}$/),
      fc.stringMatching(/^[a-z]{0,3}$/),
    ).map(([m, arg]) => `${PARAM_NAME}.${m}("${arg}")`),
    // Free function call with param arg
    fc.stringMatching(/^[a-z]{1,5}$/).map(fn => `${fn}(${PARAM_NAME})`),
  ),
})).expr;

describe("property: buildSymExpr / buildSymExprWithFlow parity", () => {
  it("both builders handle param-involving expressions consistently", () => {
    fc.assert(
      fc.property(arbExprSource, (source) => {
        let node: ts.Expression;
        try {
          node = parseExpr(source);
        } catch {
          return; // skip unparseable expressions
        }

        const fromBuildSymExpr = buildSymExpr(node, paramNames);
        const fromBuildWithFlow = buildSymExprWithFlow(node, resolveName);

        const exprResult = fromBuildSymExpr.kind !== "unknown";
        const flowResult = fromBuildWithFlow.kind !== "unknown";

        // If buildSymExpr returns non-unknown, buildSymExprWithFlow should too
        // UNLESS the result has no non-unknown leaves (the "all-unknown
        // optimization" in buildSymExprWithFlow is intentional).
        if (exprResult && !flowResult) {
          expect(hasNonUnknownLeaf(fromBuildSymExpr)).toBe(false);
        }

        // If buildSymExprWithFlow returns non-unknown, buildSymExpr must too.
        // There is no case where flow handles something that expr doesn't.
        if (flowResult) {
          expect(exprResult).toBe(true);
        }
      }),
      { numRuns: 500 },
    );
  });

  it("individual AST node types are handled by both builders", () => {
    // Fixed test cases for each AST node type — these are deterministic
    // regression anchors complementing the random property above.
    const cases: Array<{ label: string; source: string }> = [
      { label: "Identifier (param)", source: "x" },
      { label: "NumericLiteral (int)", source: "42" },
      { label: "NumericLiteral (float)", source: "3.14" },
      { label: "StringLiteral", source: '"hello"' },
      { label: "TrueKeyword", source: "true" },
      { label: "FalseKeyword", source: "false" },
      { label: "NullKeyword", source: "null" },
      { label: "BinaryExpression (eq)", source: "x === 1" },
      { label: "BinaryExpression (add)", source: "x + 1" },
      { label: "BinaryExpression (and)", source: "x && true" },
      { label: "PrefixUnaryExpression (not)", source: "!x" },
      { label: "PrefixUnaryExpression (neg)", source: "-x" },
      { label: "PrefixUnaryExpression (bitwise_not)", source: "~x" },
      { label: "PropertyAccessExpression", source: "x.length" },
      { label: "TypeOfExpression", source: "typeof x" },
      { label: "CallExpression (method)", source: 'x.indexOf("a")' },
      { label: "CallExpression (method no args)", source: "x.trim()" },
      { label: "CallExpression (free fn)", source: "parseInt(x)" },
      { label: "ParenthesizedExpression", source: "(x)" },
    ];

    for (const { label, source } of cases) {
      const node = parseExpr(source);
      const fromExpr = buildSymExpr(node, paramNames);
      const fromFlow = buildSymExprWithFlow(node, resolveName);

      // Both must return non-unknown for param-involving expressions
      if (fromExpr.kind === "unknown") {
        throw new Error(`buildSymExpr returned unknown for ${label}: ${source}`);
      }
      if (fromFlow.kind === "unknown") {
        throw new Error(`buildSymExprWithFlow returned unknown for ${label}: ${source}`);
      }
    }
  });

  it("both builders return unknown for non-param identifiers", () => {
    const node = parseExpr("unknownVar");
    const fromExpr = buildSymExpr(node, paramNames);
    const fromFlow = buildSymExprWithFlow(node, resolveName);

    expect(fromExpr.kind).toBe("unknown");
    expect(fromFlow.kind).toBe("unknown");
  });

  it("nested expressions maintain parity", () => {
    const nestedCases = [
      'x.length > 0',
      'x.indexOf("@") !== -1',
      'typeof x === "string"',
      '!(x > 0)',
      'x + 1 > 0',
    ];

    for (const source of nestedCases) {
      const node = parseExpr(source);
      const fromExpr = buildSymExpr(node, paramNames);
      const fromFlow = buildSymExprWithFlow(node, resolveName);

      if (fromExpr.kind === "unknown") {
        throw new Error(`buildSymExpr returned unknown for: ${source}`);
      }
      if (fromFlow.kind === "unknown") {
        throw new Error(`buildSymExprWithFlow returned unknown for: ${source}`);
      }
    }
  });
});

package protocol

// Error codes matching the Shatter protocol ErrorCode enum.
const (
	ErrInvalidRequest   = "invalid_request"
	ErrFileNotFound     = "file_not_found"
	ErrVersionMismatch  = "version_mismatch"
	ErrExecutionTimeout = "execution_timeout"
	ErrExecutionCrash   = "execution_crash"
	ErrCompilationError = "compilation_error"
	ErrInternalError    = "internal_error"
	ErrNotSupported     = "not_supported"
	ErrParseError       = "parse_error"
)

// CommandCapabilities lists the standard protocol commands this frontend supports.
var CommandCapabilities = []string{"analyze", "execute", "instrument", "generate", "setup", "teardown"}

package protocol

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"os"
	"strings"

	"github.com/shatter-dev/shatter/shatter-go/generators"
	"github.com/shatter-dev/shatter/shatter-go/instrument"
	"github.com/shatter-dev/shatter/shatter-go/setup"
)

const frontendVersion = "0.1.0"
const frontendLanguage = "go"

// Handler processes protocol requests and writes responses.
type Handler struct {
	reader           *bufio.Scanner
	writer           io.Writer
	log              *slog.Logger
	lastAnalyzedFile string // remembered from the most recent analyze command
	registry         *generators.Registry
	setupLoader      *setup.Loader
}

// NewHandler creates a handler reading from r, writing responses to w,
// and logging to logw at the level set by SHATTER_LOG_LEVEL.
func NewHandler(r io.Reader, w io.Writer, logw io.Writer) *Handler {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024) // 10MB max line
	return &Handler{
		reader:      scanner,
		writer:      w,
		log:         slog.New(newPrefixHandler(logw, slogLevelFromEnv())),
		registry:    generators.NewRegistry(),
		setupLoader: setup.NewLoader(),
	}
}

// NewHandlerWithLogLevel creates a handler with an explicit log level (for testing).
func NewHandlerWithLogLevel(r io.Reader, w io.Writer, logw io.Writer, level string) *Handler {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
	return &Handler{
		reader:      scanner,
		writer:      w,
		log:         slog.New(newPrefixHandler(logw, slogLevelFromString(level))),
		registry:    generators.NewRegistry(),
		setupLoader: setup.NewLoader(),
	}
}

// Run processes requests until shutdown or EOF. Returns nil on clean shutdown.
func (h *Handler) Run() error {
	h.log.Debug("Starting Go frontend", "protocol", ProtocolVersion)

	for h.reader.Scan() {
		line := h.reader.Text()
		if line == "" {
			continue
		}

		h.log.Log(context.Background(), LevelTrace, "Received", "raw", line)

		var req Request
		if err := json.Unmarshal([]byte(line), &req); err != nil {
			h.log.Log(context.Background(), LevelTrace, "Failed to parse request", "err", err)
			errResp := Response{
				ProtocolVersion: ProtocolVersion,
				ID:              0,
				Status:          "error",
				Code:            ErrInvalidRequest,
				Message:         fmt.Sprintf("Invalid JSON: %s", err.Error()),
			}
			if sendErr := h.send(errResp); sendErr != nil {
				return fmt.Errorf("writing error response: %w", sendErr)
			}
			continue
		}

		resp, shutdown := h.dispatch(req)
		if err := h.send(resp); err != nil {
			return fmt.Errorf("writing response: %w", err)
		}

		if shutdown {
			h.log.Debug("Shutting down")
			return nil
		}
	}

	if err := h.reader.Err(); err != nil {
		return fmt.Errorf("reading stdin: %w", err)
	}

	h.log.Debug("Stdin closed, exiting")
	return nil
}

func (h *Handler) dispatch(req Request) (Response, bool) {
	base := Response{
		ProtocolVersion: ProtocolVersion,
		ID:              req.ID,
	}

	if req.ProtocolVersion != ProtocolVersion {
		base.Status = "error"
		base.Code = ErrVersionMismatch
		base.Message = fmt.Sprintf(
			"unsupported protocol version %q, expected %q",
			req.ProtocolVersion, ProtocolVersion,
		)
		return base, false
	}

	switch req.Command {
	case "handshake":
		return h.handleHandshake(base, req), false
	case "analyze":
		return h.handleAnalyze(base, req), false
	case "instrument":
		return h.handleInstrument(base, req), false
	case "execute":
		return h.handleExecute(base, req), false
	case "setup":
		return h.handleSetup(base, req), false
	case "teardown":
		return h.handleTeardown(base, req), false
	case "generate":
		return h.handleGenerate(base, req), false
	case "shutdown":
		return h.handleShutdown(base), true
	default:
		base.Status = "error"
		base.Code = ErrInvalidRequest
		base.Message = fmt.Sprintf("unknown command: %s", req.Command)
		return base, false
	}
}

func (h *Handler) handleHandshake(resp Response, req Request) Response {
	resp.Status = "handshake"
	resp.FrontendVersion = frontendVersion
	resp.Language = frontendLanguage
	caps := make([]string, len(CommandCapabilities))
	copy(caps, CommandCapabilities)
	caps = append(caps,
		"complex_type:date", "complex_type:duration", "complex_type:url",
		"complex_type:reg_exp", "complex_type:ip_address", "complex_type:big_int",
		"complex_type:rational", "complex_type:big_decimal", "complex_type:error",
	)
	resp.Capabilities = caps
	return resp
}

func (h *Handler) handleAnalyze(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "analyze command requires a file path"
		return resp
	}

	if _, err := os.Stat(req.File); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("file not found: %s", req.File)
		return resp
	}

	h.lastAnalyzedFile = req.File

	var functionName string
	if req.Function != nil {
		functionName = *req.Function
	}

	functions, err := AnalyzeFile(req.File, functionName)
	if err != nil {
		if functionName != "" && isNotFound(err) {
			resp.Status = "error"
			resp.Code = "function_not_found"
			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
			return resp
		}
		resp.Status = "error"
		resp.Code = ErrParseError
		resp.Message = err.Error()
		return resp
	}

	resp.Status = "analyze"
	if functions == nil {
		functions = []FunctionAnalysis{}
	}
	resp.Functions = functions
	return resp
}

func isNotFound(err error) bool {
	return err != nil && strings.HasPrefix(err.Error(), "function not found")
}

func (h *Handler) handleInstrument(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "instrument command requires a file path"
		return resp
	}

	if _, err := os.Stat(req.File); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("file not found: %s", req.File)
		return resp
	}

	h.lastAnalyzedFile = req.File

	outputDir, err := instrument.InstrumentFile(req.File, req.Function, req.ProjectRoot)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("instrumentation failed: %v", err)
		return resp
	}

	instrumented := true
	resp.Status = "instrument"
	resp.Instrumented = &instrumented
	resp.OutputFile = &outputDir
	return resp
}

func (h *Handler) handleExecute(resp Response, req Request) Response {
	file := req.File
	if file == "" {
		file = h.lastAnalyzedFile
	}
	if file == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "execute command requires a file path (or a prior analyze)"
		return resp
	}

	if req.Function == nil || *req.Function == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "execute command requires a function name"
		return resp
	}

	if _, err := os.Stat(file); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("file not found: %s", file)
		return resp
	}

	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
	var execMocks []instrument.MockConfig
	for _, m := range req.Mocks {
		execMocks = append(execMocks, instrument.MockConfig{
			Symbol:           m.Symbol,
			ReturnValues:     m.ReturnValues,
			ShouldTrackCalls: m.ShouldTrackCalls,
			DefaultBehavior:  m.DefaultBehavior,
		})
	}
	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
	if err != nil {
		resp.Status = "error"
		if strings.Contains(err.Error(), "function not found") {
			resp.Code = "function_not_found"
		} else if strings.Contains(err.Error(), "build failed") {
			resp.Code = "instrumentation_failed"
		} else if strings.Contains(err.Error(), "timed out") {
			resp.Code = ErrExecutionTimeout
		} else {
			resp.Code = ErrInternalError
		}
		resp.Message = err.Error()
		return resp
	}

	resp.Status = "execute"
	resp.ReturnValue = result.ReturnValue
	resp.ThrownError = convertErrorInfo(result.ThrownError)
	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
	resp.BranchPath = convertBranchPath(result.BranchPath)
	resp.PathConstraints = extractPathConstraints(result.BranchPath)
	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
	resp.SideEffects = convertSideEffects(result.SideEffects)
	resp.ScopeEvents = result.ScopeEvents
	resp.Performance = &PerfMetrics{
		WallTimeMs:         result.Performance.WallTimeMs,
		CPUTimeUs:          result.Performance.CPUTimeUs,
		HeapUsedBytes:      result.Performance.HeapUsedBytes,
		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
	}

	return resp
}

func convertErrorInfo(e *instrument.ErrorInfo) *ErrorInfo {
	if e == nil {
		return nil
	}
	var stack *string
	if e.Stack != "" {
		stack = &e.Stack
	}
	return &ErrorInfo{
		ErrorType: e.ErrorType,
		Message:   e.Message,
		Stack:     stack,
	}
}

func toIntSlice(ints []int) []int {
	if ints == nil {
		return []int{}
	}
	return ints
}

func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
	result := make([]BranchDecision, len(branches))
	for i, b := range branches {
		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
		if b.ConstraintJSON != "" {
			var sc SymConstraint
			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
				constraint = &sc
			}
		}
		result[i] = BranchDecision{
			BranchID:   b.BranchID,
			Line:       b.Line,
			Taken:      b.Taken,
			Constraint: constraint,
		}
	}
	return result
}

func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
	var constraints []SymConstraint
	for _, b := range branches {
		if b.ConstraintJSON == "" {
			continue
		}
		var sc SymConstraint
		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
			constraints = append(constraints, sc)
		}
	}
	if constraints == nil {
		return []SymConstraint{}
	}
	return constraints
}

// convertExternalCalls converts executor ExternalCall records to protocol format.
func convertExternalCalls(calls []instrument.ExternalCall) []ExternalCall {
	if len(calls) == 0 {
		return []ExternalCall{}
	}
	result := make([]ExternalCall, len(calls))
	for i, c := range calls {
		var args []any
		if c.Args != nil {
			json.Unmarshal(c.Args, &args) //nolint:errcheck
		}
		var retVal any
		if c.ReturnValue != nil {
			json.Unmarshal(c.ReturnValue, &retVal) //nolint:errcheck
		}
		result[i] = ExternalCall{
			Symbol:      c.Symbol,
			Args:        args,
			ReturnValue: retVal,
		}
	}
	return result
}

// convertSideEffects converts executor SideEffects to protocol format.
func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
	if len(effects) == 0 {
		return []SideEffect{}
	}
	result := make([]SideEffect, len(effects))
	for i, e := range effects {
		result[i] = SideEffect{
			Kind:    e.Kind,
			Level:   e.Level,
			Message: e.Message,
		}
	}
	return result
}

func (h *Handler) handleSetup(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "setup command requires a file path"
		return resp
	}
	if req.Scope == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "setup command requires a scope"
		return resp
	}
	if !req.Level.IsValid() {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
		return resp
	}

	if _, err := os.Stat(req.File); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
		return resp
	}

	var parentCtxJSON json.RawMessage
	if req.ParentContext != nil {
		data, err := json.Marshal(req.ParentContext)
		if err != nil {
			resp.Status = "error"
			resp.Code = ErrInternalError
			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
			return resp
		}
		parentCtxJSON = data
	}

	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)

	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("setup failed: %v", err)
		return resp
	}

	resp.Status = "setup"
	ctxCopy := json.RawMessage(ctx)
	resp.SetupContext = &ctxCopy
	return resp
}

func (h *Handler) handleTeardown(resp Response, req Request) Response {
	if req.Scope == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "teardown command requires a scope"
		return resp
	}
	if !req.Level.IsValid() {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
		return resp
	}

	h.log.Debug("Running teardown", "scope", req.Scope, "level", req.Level)

	h.setupLoader.Teardown(req.Scope, string(req.Level))

	resp.Status = "teardown_ack"
	return resp
}

func (h *Handler) handleGenerate(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "generate command requires a file path"
		return resp
	}
	if req.Name == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "generate command requires a name"
		return resp
	}

	var recipe json.RawMessage
	if req.Recipe != nil {
		recipe = *req.Recipe
	}

	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("generate failed: %v", err)
		return resp
	}

	resp.Status = "generate"
	valCopy := json.RawMessage(value)
	resp.Value = &valCopy
	resp.GeneratorID = generatorID
	if outRecipe != nil {
		recipeCopy := json.RawMessage(outRecipe)
		resp.Recipe = &recipeCopy
	}
	return resp
}

// Registry returns the generator registry, allowing custom builds to register
// native generators before calling Run().
func (h *Handler) Registry() *generators.Registry {
	return h.registry
}

func (h *Handler) handleShutdown(resp Response) Response {
	h.registry.Close()
	h.setupLoader.Close()
	resp.Status = "shutdown_ack"
	return resp
}

func (h *Handler) send(resp Response) error {
	data, err := json.Marshal(resp)
	if err != nil {
		return fmt.Errorf("marshaling response: %w", err)
	}
	line := string(data) + "\n"
	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
	_, err = io.WriteString(h.writer, line)
	return err
}

package protocol

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"os"
	"strings"

	"github.com/shatter-dev/shatter/shatter-go/generators"
