    // -- Exec timeout tests --
    // SAFETY: env var mutations in tests are inherently racy but acceptable for unit tests.
    // These tests exercise exec_timeout_from_env() which only reads SHATTER_EXEC_TIMEOUT.

    #[test]
    fn exec_timeout_default_is_5000ms() {
