        std::fs::create_dir_all(&dir).unwrap();
        let file = dir.join("sample.rs");
        std::fs::write(&file, "fn foo(x: i32) -> bool { if x > 0 { true } else { false } }").unwrap();

        let file_path = file.to_string_lossy();
